  if (dSup < 0.5) { score += 12; reasons.push('Double Bottom \u2705'); confluenceCount++; }
  else if (dSup < 1.5) { score += 7; reasons.push('Near support (' + dSup.toFixed(1) + '%)'); confluenceCount++; }
  else if (dSup < 3) { score += 3; }

  if (range > 0 && lowerWick/range > 0.5) { score += 7; reasons.push('Buyer wick \u2191'); }
  else if (range > 0 && lowerWick/range > 0.3) { score += 4; }
  if (_adx < 20) { score += 5; reasons.push('ADX weak — mean revert'); }
  else if (_adx > 40) { score -= 5; reasons.push('ADX strong \u26a0\ufe0f'); }

  // RSI Bullish Divergence
  if (_rsiDiv.bullish) { score += 20; reasons.push('\ud83d\udd25 RSI BULL DIVERGENCE'); confluenceCount++; }

  // OBV
  if (_obvTrend === 'RISING') { score += 10; reasons.push('OBV RISING — accumulation \u2705'); confluenceCount++; }
  else { score += 3; reasons.push('OBV neutral'); }

  // BONUS
  if (ema9CrossAbove21) { score += 8; reasons.push('EMA 9/21 Bull Cross \u2705'); }
  if (priceBelowLowerBB) { score += 5; reasons.push('Below BB Lower \u2705'); }
  if (trend4hBias === 'BULLISH') { score += 10; reasons.push('4H UPTREND \u2705'); }
  else { score += 3; reasons.push('4H Sideways'); }

  if (confluenceCount < 4) return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udeab CONFLUENCE: ' + confluenceCount + '/9 (min 4). Score ' + score } }];

  if (score >= 75) { signal = 'STRONG BUY'; strategy = 'LONG (Buy Dip)'; confidence = 'VERY HIGH'; }
  else if (score >= 65) { signal = 'STRONG BUY'; strategy = 'LONG (Buy Dip)'; confidence = 'HIGH'; }
  else { reasons.push('Score ' + score + ' < 65'); }
}

// ═══ STRATEGY 2 & 3: PUMP ═══
else if (wsPctChange >= dynamicThreshold) {
  let shortScore = 0, breakoutScore = 0;
  const shortReasons = [], breakoutReasons = [];
  let shortConfluence = 0, breakoutConfluence = 0;

  // SHORT
  const shortGatePass = (_rsi >= 65) && isRed && (trend4hBias !== 'BULLISH') && (_obvTrend !== 'RISING');
  if (shortGatePass) {
